import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Trash2, Heart, CheckCircle2 } from 'lucide-react';
import { useWishlist } from '../hooks/useWishlist';
import { useCart } from '../hooks/usecart';

const WishlistPage = () => {
    const { items = [], removeItem } = useWishlist();
    const { items: cartItems = [], addItem } = useCart();
    const navigate = useNavigate();

    // 🚀 Bulletproof Filter: Removes nulls to strictly match the logic in Navbar
    const validItems = items.filter(item => item && (item.productId || item._id || item.id));

    // ==========================================
    // PREMIUM TOAST NOTIFICATION SYSTEM
    // ==========================================
    const [toast, setToast] = useState({ show: false, message: '', type: 'success' });
    const toastTimer = useRef(null);

    const showToast = (message, type = 'success') => {
        if (toastTimer.current) clearTimeout(toastTimer.current);
        setToast({ show: true, message, type });
        toastTimer.current = setTimeout(() => {
            setToast(prev => ({ ...prev, show: false }));
        }, 1000); // 1 second
    };

    useEffect(() => {
        return () => {
            if (toastTimer.current) clearTimeout(toastTimer.current);
        };
    }, []);

    // BULLETPROOF MATH
    const getSafePrice = (item) => Number(item.price || item.finalPrice || item.variants?.[0]?.price) || 0;
    const getSafeMrp = (item) => {
        const mrp = Number(item.mrp || item.originalPrice || item.compare_price);
        return mrp > 0 ? mrp : Math.round(getSafePrice(item) * 1.25);
    };

    const handleAddToCart = (item) => {
        const safeId = item.productId || item._id || item.id;
        const isInCart = cartItems.some(cItem => String(cItem.productId) === String(safeId));

        if (isInCart) {
            navigate('/cart');
            return;
        }

        if (addItem) {
            const safePrice = getSafePrice(item);
            const safeMrp = getSafeMrp(item);

            const normalizedProduct = {
                ...item,
                _id: safeId,
                name: item.name || 'Premium Furniture',
                price: safePrice,
                images: [{ url: item.image || 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=800&q=80' }]
            };

            const selectedVariant = {
                variant_id: item.variantId || 'default',
                price: safePrice,
                compare_price: safeMrp
            };

            addItem(normalizedProduct, selectedVariant, 1);
            showToast(`${item.name || 'Item'} added to Cart!`);
        }
    };

    if (validItems.length === 0) {
        return (
            <div className="bg-[#f4f5f7] min-h-[70vh] flex flex-col items-center justify-center px-4 py-16 font-sans">
                <div className="bg-white p-12 rounded-2xl shadow-sm border border-gray-100 text-center max-w-lg w-full">
                    <div className="w-24 h-24 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6">
                        <Heart size={40} className="text-red-400 fill-red-100" />
                    </div>
                    <h2 className="text-2xl font-bold text-gray-900 mb-3 tracking-tight">Your wishlist is empty</h2>
                    <p className="text-gray-500 mb-8">Save your favorite premium furniture pieces here to review them later.</p>
                    <Link
                        to="/"
                        className="inline-block bg-[#f97316] text-white px-8 py-3.5 rounded-xl font-bold hover:bg-black transition-all duration-300 w-full tracking-wide shadow-md hover:shadow-black/20 active:scale-[0.98] outline-none focus:outline-none focus:ring-0 focus-visible:outline-none select-none"
                    >
                        DISCOVER PRODUCTS
                    </Link>
                </div>
            </div>
        );
    }

    return (
        <div className="bg-[#f4f5f7] min-h-screen py-10 font-sans relative overflow-hidden">

            {/* Custom Dark Popup Toast */}
            <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] transition-all duration-500 ease-[cubic-bezier(0.175,0.885,0.32,1.275)] pointer-events-none ${toast.show ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-12 scale-90'
                }`}>
                <div className="bg-[#222222] text-white px-5 py-3.5 rounded-xl shadow-2xl flex items-center gap-4 min-w-max">
                    <span className="text-[15px] font-medium tracking-wide">
                        {toast.message}
                    </span>
                    <button
                        onClick={(e) => {
                            e.preventDefault();
                            navigate('/cart');
                        }}
                        className="px-7 py-2.5 rounded-full text-[15px] font-medium transition-colors duration-200 select-none border-none !shadow-none !outline-none focus:!outline-none focus:!ring-0 focus:!ring-offset-0 focus-visible:!outline-none bg-[#f97316] text-white pointer-events-auto"
                        style={{
                            WebkitTapHighlightColor: 'transparent',
                            outline: 'none',
                            boxShadow: 'none',
                        }}
                    >
                        GO TO CART
                    </button>
                </div>
            </div>

            <div className="container mx-auto px-4 max-w-4xl">
                <div className="mb-8">
                    <h1 className="text-2xl md:text-3xl font-bold text-gray-900 tracking-tight flex items-center gap-3">
                        My Wishlist
                        <span className="text-gray-500 font-medium text-lg bg-gray-200/60 px-3.5 py-1 rounded-full">
                            {validItems.length} {validItems.length === 1 ? 'Item' : 'Items'}
                        </span>
                    </h1>
                </div>

                <div className="flex flex-col gap-5">
                    {validItems.map((item, index) => {
                        const price = getSafePrice(item);
                        const mrp = getSafeMrp(item);
                        const discountPercent = mrp > price && price > 0 ? Math.round(((mrp - price) / mrp) * 100) : 0;

                        const safeId = item.productId || item._id || item.id;
                        const isInCart = cartItems.some(cItem => String(cItem.productId) === String(safeId));

                        return (
                            <div key={`${safeId}_${item.variantId}_${index}`} className="bg-white rounded-2xl p-5 shadow-sm border border-gray-100 flex flex-col sm:flex-row gap-6 hover:border-gray-200 hover:shadow-md transition-all duration-300 group">

                                <div className="shrink-0 overflow-hidden rounded-xl border border-gray-100 bg-gray-50 w-full sm:w-40 h-40 cursor-pointer">
                                    <Link to={`/product/${safeId}`} className="outline-none focus:outline-none border-none select-none" style={{ WebkitTapHighlightColor: 'transparent' }}>
                                        <img
                                            src={item.image || 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=800&q=80'}
                                            alt={item.name || 'Product Image'}
                                            className="w-full h-full object-cover transform transition-transform duration-700 ease-out group-hover:scale-105"
                                            onError={(e) => {
                                                e.target.onerror = null;
                                                e.target.src = 'https://images.unsplash.com/photo-1493663284031-b7e3aefcae8e?w=800&q=80';
                                            }}
                                        />
                                    </Link>
                                </div>

                                <div className="flex-1 flex flex-col justify-between">
                                    <div className="flex justify-between items-start gap-4">
                                        <div>
                                            <Link to={`/product/${safeId}`} className="outline-none focus:outline-none border-none select-none" style={{ WebkitTapHighlightColor: 'transparent' }}>
                                                <h3 className="text-lg font-bold text-gray-900 tracking-tight leading-snug group-hover:text-[#f97316] transition-colors duration-300">
                                                    {item.name || 'Premium Furniture'}
                                                </h3>
                                            </Link>
                                            {item.variantId && (
                                                <p className="text-sm text-gray-500 mt-1 font-medium">Variant: {String(item.variantId).replace('var_', '')}</p>
                                            )}
                                        </div>
                                        {/* 🚀 KILLED THE GHOST LINE: Added strict !outline-none, !ring-0, !ring-offset-0, !shadow-none overrides */}
                                        <button
                                            onClick={() => removeItem(safeId, item.variantId)}
                                            className="p-2.5 text-red-500 bg-red-50 border border-red-200 hover:bg-red-100 hover:border-red-300 rounded-xl transition-all duration-200 active:scale-90 select-none !outline-none focus:!outline-none focus-visible:!outline-none !ring-0 !ring-offset-0 focus:!ring-0 !shadow-none"
                                            title="Remove from Wishlist"
                                            style={{ WebkitTapHighlightColor: 'transparent', outline: 'none', boxShadow: 'none' }}
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    </div>

                                    <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-5 mt-6 sm:mt-0">
                                        <div className="flex flex-col">
                                            {discountPercent > 0 && (
                                                <span className="text-[11px] font-bold tracking-wider text-[#22c55e] mb-1 uppercase">Limited-Time Deal</span>
                                            )}
                                            <div className="flex items-baseline gap-2.5">
                                                <span className="text-2xl font-bold text-gray-900 tracking-tight">₹{price.toLocaleString('en-IN')}</span>
                                                {mrp > price && (
                                                    <span className="text-sm text-gray-400 line-through font-medium">₹{mrp.toLocaleString('en-IN')}</span>
                                                )}
                                                {discountPercent > 0 && (
                                                    <span className="text-sm font-bold text-[#22c55e]">{discountPercent}% OFF</span>
                                                )}
                                            </div>
                                        </div>

                                        {/* Main Action Button */}
                                        <button
                                            onClick={() => handleAddToCart(item)}
                                            className={`w-full sm:w-auto min-w-[140px] px-7 py-2.5 rounded-lg text-[15px] font-medium transition-colors duration-200 select-none !shadow-none !outline-none focus:!outline-none focus:!ring-0 focus:!ring-offset-0 focus-visible:!outline-none active:scale-[0.98] ${isInCart
                                                    ? 'bg-[#10b981] text-white border border-transparent hover:bg-[#059669]'
                                                    : 'bg-transparent text-gray-800 border border-gray-200 hover:bg-gray-50'
                                                }`}
                                            style={{
                                                WebkitTapHighlightColor: 'transparent',
                                                outline: 'none',
                                                boxShadow: 'none',
                                            }}
                                        >
                                            {isInCart ? 'Go to Cart' : 'Move to Cart'}
                                        </button>

                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};

export default WishlistPage;
